package com.example.recyclerview
import android.os.Bundle import android.widget.Toast import androidx.appcompat.app.AppCompatActivity import androidx.recyclerview.widget.LinearLayoutManager import androidx.recyclerview.widget.RecyclerView
class MainActivity : AppCompatActivity() {
private lateinit var recyclerView: RecyclerView private lateinit var adapter: TaskAdapter private val taskList = mutableListOf<Task>()
override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) setContentView(R.layout.activity_main)
// Datos de ejemplo con distintas prioridades taskList.addAll( listOf( Task(1, "Entregar informe mensual", "Trabajo", Priority.HIGH), Task(2, "Revisar correos pendientes", "Trabajo", Priority.MEDIUM), Task(3, "Comprar ingredientes", "Personal", Priority.LOW), Task(4, "Llamar al médico", "Salud", Priority.HIGH), Task(5, "Actualizar documentación", "Proyecto", Priority.MEDIUM), Task(6, "Hacer ejercicio", "Salud", Priority.LOW), Task(7, "Preparar presentación", "Trabajo", Priority.HIGH), Task(8, "Leer libro de Kotlin", "Formación", Priority.LOW), Task(9, "Pagar facturas", "Finanzas", Priority.MEDIUM), Task(10,"Organizar escritorio", "Personal", Priority.LOW) ) )
// Ordenar: ALTA (rojo) → MEDIA (amarillo) → BAJA (verde) taskList.sortBy { it.priority.ordinal }
adapter = TaskAdapter( tasks = taskList, onTaskClick = { task -> // Cambiar estado completado y refrescar el ítem task.isCompleted = !task.isCompleted val pos = taskList.indexOf(task) adapter.notifyItemChanged(pos) Toast.makeText(this, "Completando... ${task.title}", Toast.LENGTH_SHORT).show() }, onTaskDelete = { _ -> Toast.makeText(this, "Tarea eliminada", Toast.LENGTH_SHORT).show() } )
recyclerView = findViewById(R.id.recyclerView) recyclerView.layoutManager = LinearLayoutManager(this) recyclerView.adapter = adapter } }

package com.example.recyclerview

import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView

class MainActivity : AppCompatActivity() {

    private lateinit var recyclerView: RecyclerView
    private lateinit var adapter: TaskAdapter
    private val taskList = mutableListOf<Task>()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        // Datos de ejemplo con distintas prioridades
        taskList.addAll(
            listOf(
                Task(1, "Entregar informe mensual",   "Trabajo",   Priority.HIGH),
                Task(2, "Revisar correos pendientes", "Trabajo",   Priority.MEDIUM),
                Task(3, "Comprar ingredientes",       "Personal",  Priority.LOW),
                Task(4, "Llamar al médico",           "Salud",     Priority.HIGH),
                Task(5, "Actualizar documentación",   "Proyecto",  Priority.MEDIUM),
                Task(6, "Hacer ejercicio",            "Salud",     Priority.LOW),
                Task(7, "Preparar presentación",      "Trabajo",   Priority.HIGH),
                Task(8, "Leer libro de Kotlin",       "Formación", Priority.LOW),
                Task(9, "Pagar facturas",             "Finanzas",  Priority.MEDIUM),
                Task(10,"Organizar escritorio",       "Personal",  Priority.LOW)
            )
        )

        // Ordenar: ALTA (rojo) → MEDIA (amarillo) → BAJA (verde)
        taskList.sortBy { it.priority.ordinal }

        adapter = TaskAdapter(
            tasks = taskList,
            onTaskClick = { task ->
                // El adaptador ya cambió isCompleted y llamó a notifyItemChanged
                Toast.makeText(this, "Completando... ${task.title}", Toast.LENGTH_SHORT).show()
            },
            onTaskDelete = { _ ->
                Toast.makeText(this, "Tarea eliminada", Toast.LENGTH_SHORT).show()
            }
        )

        recyclerView = findViewById(R.id.recyclerView)
        recyclerView.layoutManager = LinearLayoutManager(this)
        recyclerView.adapter = adapter
    }
}

package com.example.recyclerview

import android.graphics.Paint
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.ImageButton
import android.widget.TextView
import androidx.cardview.widget.CardView
import androidx.core.graphics.toColorInt
import androidx.recyclerview.widget.RecyclerView

class TaskAdapter(
    private val tasks: MutableList<Task>,
    private val onTaskClick: (Task) -> Unit,
    private val onTaskDelete: (Int) -> Unit
) : RecyclerView.Adapter<TaskAdapter.TaskViewHolder>() {

    class TaskViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        val cardView: CardView      = itemView.findViewById(R.id.cardView)
        val tvTitle: TextView       = itemView.findViewById(R.id.tvTitle)
        val tvCategory: TextView    = itemView.findViewById(R.id.tvCategory)
        val viewBanner: View        = itemView.findViewById(R.id.viewBanner)   // franja de color
        val viewPriority: View      = itemView.findViewById(R.id.viewPriority) // círculo chincheta
        val btnDelete: ImageButton  = itemView.findViewById(R.id.btnDelete)
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): TaskViewHolder {
        val view = LayoutInflater.from(parent.context)
            .inflate(R.layout.item_task, parent, false)
        return TaskViewHolder(view)
    }

    override fun onBindViewHolder(holder: TaskViewHolder, position: Int) {
        val task = tasks[position]

        holder.tvTitle.text    = task.title
        holder.tvCategory.text = task.category

        if (task.isCompleted) {
            // ── Tarea completada: tarjeta atenuada con tachado ──
            val grayColor = "#9E9E9E".toColorInt()
            holder.viewBanner.setBackgroundColor(grayColor)
            holder.viewPriority.setBackgroundResource(R.drawable.circle_gray)
            holder.tvTitle.setTextColor("#9E9E9E".toColorInt())
            holder.tvTitle.paintFlags =
                holder.tvTitle.paintFlags or Paint.STRIKE_THRU_TEXT_FLAG
            holder.cardView.alpha = 0.72f
        } else {
            // ── Tarea pendiente: colores de madera + prioridad ──
            holder.tvTitle.setTextColor("#3E2723".toColorInt())
            holder.tvTitle.paintFlags =
                holder.tvTitle.paintFlags and Paint.STRIKE_THRU_TEXT_FLAG.inv()
            holder.cardView.alpha = 1.0f

            when (task.priority) {
                Priority.HIGH -> {
                    holder.viewBanner.setBackgroundColor("#E53935".toColorInt())
                    holder.viewPriority.setBackgroundResource(R.drawable.circle_red)
                }
                Priority.MEDIUM -> {
                    holder.viewBanner.setBackgroundColor("#F9A825".toColorInt())
                    holder.viewPriority.setBackgroundResource(R.drawable.circle_yellow)
                }
                Priority.LOW -> {
                    holder.viewBanner.setBackgroundColor("#388E3C".toColorInt())
                    holder.viewPriority.setBackgroundResource(R.drawable.circle_green)
                }
            }
        }

        // Click en la nota: completar + Toast
        holder.cardView.setOnClickListener {
            onTaskClick(task)
        }

        // Click en el botón eliminar
        holder.btnDelete.setOnClickListener {
            val currentPosition = holder.bindingAdapterPosition
            if (currentPosition != RecyclerView.NO_POSITION) {
                tasks.removeAt(currentPosition)
                notifyItemRemoved(currentPosition)
                onTaskDelete(currentPosition)
            }
        }
    }

    override fun getItemCount(): Int = tasks.size
}

package com.example.recyclerview

import android.graphics.Paint
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.ImageButton
import android.widget.TextView
import androidx.cardview.widget.CardView
import androidx.core.graphics.toColorInt
import androidx.recyclerview.widget.RecyclerView

class TaskAdapter(
    private val tasks: MutableList<Task>,
    private val onTaskClick: (Task) -> Unit,
    private val onTaskDelete: (Int) -> Unit
) : RecyclerView.Adapter<TaskAdapter.TaskViewHolder>() {

    class TaskViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        val cardView: CardView      = itemView.findViewById(R.id.cardView)
        val tvTitle: TextView       = itemView.findViewById(R.id.tvTitle)
        val tvCategory: TextView    = itemView.findViewById(R.id.tvCategory)
        val viewBanner: View        = itemView.findViewById(R.id.viewBanner)   // franja de color
        val viewPriority: View      = itemView.findViewById(R.id.viewPriority) // círculo chincheta
        val btnDelete: ImageButton  = itemView.findViewById(R.id.btnDelete)
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): TaskViewHolder {
        val view = LayoutInflater.from(parent.context)
            .inflate(R.layout.item_task, parent, false)
        return TaskViewHolder(view)
    }

    override fun onBindViewHolder(holder: TaskViewHolder, position: Int) {
        val task = tasks[position]

        holder.tvTitle.text    = task.title
        holder.tvCategory.text = task.category

        if (task.isCompleted) {
            // ── Tarea completada: tarjeta atenuada con tachado ──
            val grayColor = "#9E9E9E".toColorInt()
            holder.viewBanner.setBackgroundColor(grayColor)
            holder.viewPriority.setBackgroundResource(R.drawable.circle_gray)
            holder.tvTitle.setTextColor("#9E9E9E".toColorInt())
            holder.tvTitle.paintFlags =
                holder.tvTitle.paintFlags or Paint.STRIKE_THRU_TEXT_FLAG
            holder.cardView.alpha = 0.72f
        } else {
            // ── Tarea pendiente: colores de madera + prioridad ──
            holder.tvTitle.setTextColor("#3E2723".toColorInt())
            holder.tvTitle.paintFlags =
                holder.tvTitle.paintFlags and Paint.STRIKE_THRU_TEXT_FLAG.inv()
            holder.cardView.alpha = 1.0f

            when (task.priority) {
                Priority.HIGH -> {
                    holder.viewBanner.setBackgroundColor("#E53935".toColorInt())
                    holder.viewPriority.setBackgroundResource(R.drawable.circle_red)
                }
                Priority.MEDIUM -> {
                    holder.viewBanner.setBackgroundColor("#F9A825".toColorInt())
                    holder.viewPriority.setBackgroundResource(R.drawable.circle_yellow)
                }
                Priority.LOW -> {
                    holder.viewBanner.setBackgroundColor("#388E3C".toColorInt())
                    holder.viewPriority.setBackgroundResource(R.drawable.circle_green)
                }
            }
        }

        // Click en la nota: completar + Toast
        holder.cardView.setOnClickListener {
            val pos = holder.bindingAdapterPosition
            if (pos != RecyclerView.NO_POSITION) {
                val clickedTask = tasks[pos]
                clickedTask.isCompleted = !clickedTask.isCompleted
                notifyItemChanged(pos)
                onTaskClick(clickedTask)
            }
        }

        // Click en el botón eliminar
        holder.btnDelete.setOnClickListener {
            val currentPosition = holder.bindingAdapterPosition
            if (currentPosition != RecyclerView.NO_POSITION) {
                tasks.removeAt(currentPosition)
                notifyItemRemoved(currentPosition)
                onTaskDelete(currentPosition)
            }
        }
    }

    override fun getItemCount(): Int = tasks.size
}
